1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	
33	const FIRST_INSURANCE_SURCHARGE = 0.1;
34	const CURSE_SURCHARGE = 0.5;
35	const PROCESSING_FEE = 5;
36	
37	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
38	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
39	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
40	
41	// A block applies only to a group of exactly BLOCK_SIZE alike components,
42	// priced at BLOCK_PREMIUM; any other count is priced individually.
43	const componentBasePremium = (count: number, perComponent: number): number => {
44	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
45	  return count * perComponent;
46	};
47	
48	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
49	
50	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
51	const isMainItem = (item: Item): boolean => !isComponent(item);
52	
53	const countByType = (items: Item[]): Record<string, number> => {
54	  const counts: Record<string, number> = {};
55	  for (const item of items) {
56	    counts[item.type] = (counts[item.type] ?? 0) + 1;
57	  }
58	  return counts;
59	};
60	
61	// Item-specific surcharges are additive percentages of the item's base premium.
62	// First insurance applies to every item; the curse surcharge to cursed items.
63	const itemSurchargeRate = (item: Item): number => {
64	  const curse = item.cursed ? CURSE_SURCHARGE : 0;
65	  return FIRST_INSURANCE_SURCHARGE + curse;
66	};
67	
68	const mainItemPremium = (item: Item): number =>
69	  BASE_PREMIUM[item.type] * (1 + itemSurchargeRate(item));
70	
71	const componentGroupPremium = (count: number, perComponent: number): number =>
72	  componentBasePremium(count, perComponent) * (1 + FIRST_INSURANCE_SURCHARGE);
73	
74	const itemsPremium = (items: Item[]): number => {
75	  const componentCounts = countByType(items.filter(isComponent));
76	
77	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
78	  const componentsPremium = sum(
79	    Object.entries(componentCounts).map(([type, count]) =>
80	      componentGroupPremium(count, BASE_PREMIUM[type]),
81	    ),
82	  );
83	
84	  return mainItemsPremium + componentsPremium;
85	};
86	
87	const quotePremium = (items: Item[]): number =>
88	  roundPremiumUp(itemsPremium(items) + PROCESSING_FEE);
89	
90	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
91	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
92	  return { results };
93	};
